sys_variable_value.value:
(function execute(inputs, outputs) {
try {
var reservedFor = inputs.reserved_for ?
inputs.reserved_for.getValue('name') : 'Unknown';

var workspace = inputs.workspace ?
inputs.workspace.getValue('workspace_name') : 'Unknown';

var startDate = 'Unknown';
if (inputs.start_date_time) {
var gdt = new GlideDateTime();
gdt.setValue(inputs.start_date_time + '');
startDate = gdt.getDisplayValue();
}

var trackerLink = ''; 
if (inputs.tracker_record) { 
var instanceURL = 
gs.getProperty('glide.servlet.uri'); 
var tableName = 
inputs.tracker_record.getRecordClassName(); 
var sysId = inputs.tracker_record.getUniqueValue(); 
trackerLink = instanceURL + tableName + 
'.do?sys_id=' + sysId; 
}

var message = 'Workspace reservation approved for ' + reservedFor +
' - ' + workspace +
' on ' + startDate;

if (trackerLink) { 
message += '\n🔗 View Tracker Record: ' +  trackerLink; 
} 
message += '\n📋 Please claim this reservation to begin preparation.'; 


var discord = new discordNotification();
discord.sendMessage(message, '✅');
} catch (ex) {
gs.error('Discord error: ' + ex.message);
}

})(inputs, outputs);

